using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainingService
{
    private readonly MLContext _mlContext;
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly ILogger<ModelTrainingService> _logger;
    private TrainingMetricsResponse? _lastMetrics;

    public ModelTrainingService(ILogger<ModelTrainingService> logger, IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
        _logger = logger;
    }

    public TrainingMetricsResponse Train()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Featurize text columns and combine with Priority into a single Features vector
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, "Label");

        _lastMetrics = new TrainingMetricsResponse
        {
            MacroAccuracy = metrics.MacroAccuracy,
            MicroAccuracy = metrics.MicroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction
        };

        _logger.LogInformation(
            "Model trained — MacroAccuracy: {MacroAccuracy:F4}, MicroAccuracy: {MicroAccuracy:F4}, LogLoss: {LogLoss:F4}",
            metrics.MacroAccuracy, metrics.MicroAccuracy, metrics.LogLoss);

        _mlContext.Model.Save(model, split.TrainSet.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);

        return _lastMetrics;
    }

    public TrainingMetricsResponse? GetLastMetrics() => _lastMetrics;

    public string GetModelPath() => _modelPath;
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private readonly ModelTrainingService _trainingService;

    public TicketsController(
        PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
        ModelTrainingService trainingService)
    {
        _predictionPool = predictionPool;
        _trainingService = trainingService;
    }

    /// <summary>Trains (or retrains) the model and returns evaluation metrics.</summary>
    [HttpPost("train")]
    public ActionResult<TrainingMetricsResponse> Train()
    {
        var metrics = _trainingService.Train();
        return Ok(metrics);
    }

    /// <summary>Returns metrics from the most recent training run.</summary>
    [HttpGet("metrics")]
    public ActionResult<TrainingMetricsResponse> GetMetrics()
    {
        var metrics = _trainingService.GetLastMetrics();
        if (metrics is null)
            return NotFound("Model has not been trained yet. POST to /api/tickets/train first.");

        return Ok(metrics);
    }

    /// <summary>Predicts the category for a support ticket.</summary>
    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        string[] labels = ["Billing", "General", "Technical"];
        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < labels.Length && i < prediction.Score.Length; i++)
            confidence[labels[i]] = prediction.Score[i];

        return Ok(new TicketPredictionResponse
        {
            Category = prediction.Category,
            Confidence = confidence
        });
    }
}

